-- تعديل قيود الجدول للسماح بالأقسام الجديدة
ALTER TABLE products DROP CONSTRAINT IF EXISTS products_category_check;
ALTER TABLE products ADD CONSTRAINT products_category_check CHECK (category IN ('android', 'ios', 'laptops', 'pcs', 'monitors', 'accessories', 'apple-watches', 'other-watches'));


